# Probe: which S3 encryption styles satisfy trivy AWS-0132?

# variant 1: SSE-S3 (AES256, S3-managed key)
resource "aws_s3_bucket" "v1_sse_s3" {
  bucket = "v1-sse-s3"
}
resource "aws_s3_bucket_server_side_encryption_configuration" "v1_sse_s3" {
  bucket = aws_s3_bucket.v1_sse_s3.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# variant 2: aws:kms with NO key id (aws/s3 default AWS-managed KMS key)
resource "aws_s3_bucket" "v2_kms_managed" {
  bucket = "v2-kms-managed"
}
resource "aws_s3_bucket_server_side_encryption_configuration" "v2_kms_managed" {
  bucket = aws_s3_bucket.v2_kms_managed.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms"
    }
  }
}

# variant 3: aws:kms with a real CMK arn (control, should PASS)
resource "aws_s3_bucket" "v3_kms_cmk" {
  bucket = "v3-kms-cmk"
}
resource "aws_s3_bucket_server_side_encryption_configuration" "v3_kms_cmk" {
  bucket = aws_s3_bucket.v3_kms_cmk.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = "arn:aws:kms:eu-west-1:111122223333:key/demo-key"
    }
  }
}

# variant 4: no encryption config (control, should FAIL = current module default)
resource "aws_s3_bucket" "v4_none" {
  bucket = "v4-none"
}

