# Probe A1: does trivy AWS-0132 pass when the CMK is a RESOURCE REFERENCE
# (root-created key) feeding a CONDITIONAL-count SSE config (module as-is)?

variable "enable_encryption" {
  type    = bool
  default = true
}

resource "aws_kms_key" "ex" {
  description = "root-created CMK"
}

# bucket A: module-as-is style -> conditional count keyed on enable_encryption && key!=null
locals {
  kms_enabled = var.enable_encryption && aws_kms_key.ex.arn != null
}
resource "aws_s3_bucket" "a_conditional" {
  bucket = "probe-a-conditional"
}
resource "aws_s3_bucket_server_side_encryption_configuration" "a_conditional" {
  count  = local.kms_enabled ? 1 : 0
  bucket = aws_s3_bucket.a_conditional.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.ex.arn
    }
  }
}

# bucket B: deferred-actions style -> SSE always attached, key is the reference
resource "aws_s3_bucket" "b_always" {
  bucket = "probe-b-always"
}
resource "aws_s3_bucket_server_side_encryption_configuration" "b_always" {
  bucket = aws_s3_bucket.b_always.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = "aws:kms"
      kms_master_key_id = aws_kms_key.ex.arn
    }
  }
}

